def max_coins(nums: list[int]) -> int:
    if not nums:
        return 0
    n = len(nums)
    A = [1] + nums + [1]
    dp = [[0] * (n + 2) for _ in range(n + 2)]

    for length in range(1, n + 1):
        for i in range(1, n - length + 2):
            j = i + length - 1
            for k in range(i, j + 1):
                dp[i][j] = max(dp[i][j], dp[i][k-1] + dp[k+1][j] + A[i-1] * A[k] * A[j+1])

    return dp[1][n]

class DirectedGraph:
    def __init__(self, n: int):
        self.n = n
        self.adj = [[] for _ in range(n)]
        self.in_degree = [0] * n

    def add_edge(self, u: int, v: int) -> None:
        self.adj[u].append(v)
        self.in_degree[v] += 1

    def has_cycle(self) -> bool:
        in_deg = self.in_degree[:]
        queue = [i for i in range(self.n) if in_deg[i] == 0]
        count = 0
        while queue:
            u = queue.pop(0)
            count += 1
            for v in self.adj[u]:
                in_deg[v] -= 1
                if in_deg[v] == 0:
                    queue.append(v)
        return count < self.n

    def topological_sort(self) -> list[int] | None:
        if self.has_cycle():
            return None
        in_deg = self.in_degree[:]
        queue = [i for i in range(self.n) if in_deg[i] == 0]
        order = []
        while queue:
            u = queue.pop(0)
            order.append(u)
            for v in self.adj[u]:
                in_deg[v] -= 1
                if in_deg[v] == 0:
                    queue.append(v)
        return order

    def all_topological_sorts(self) -> list[list[int]]:
        if self.has_cycle():
            return []

        results = []
        in_deg = self.in_degree[:]
        path = []

        def backtrack():
            if len(path) == self.n:
                results.append(path[:])
                return
            for i in range(self.n):
                if in_deg[i] == 0:
                    path.append(i)
                    in_deg[i] = -1
                    for v in self.adj[i]:
                        in_deg[v] -= 1
                    backtrack()
                    for v in self.adj[i]:
                        in_deg[v] += 1
                    in_deg[i] = 0
                    path.pop()

        backtrack()
        return results

    def longest_path(self) -> int:
        if self.has_cycle():
            return -1

        topo = self.topological_sort()
        dist = [0] * self.n
        max_len = 0

        for u in topo:
            for v in self.adj[u]:
                if dist[u] + 1 > dist[v]:
                    dist[v] = dist[u] + 1
                    if dist[v] > max_len:
                        max_len = dist[v]

        return max_len

from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self.events: list[Event] = []

    def add_event(self, event: Event) -> list[Event]:
        if event.start >= event.end:
            raise ValueError("Start must be less than end")

        overlaps = [e for e in self.events if e.start < event.end and e.end > event.start]
        if not overlaps:
            self.events.append(event)
            return []

        overlaps.sort(key=lambda e: e.start)

        returned = []
        new_fragments = []

        # Higher priority new event trims lower priority existing
        for existing in [e for e in overlaps if e.priority < event.priority]:
            if event.start <= existing.start and event.end >= existing.end:
                self.events.remove(existing)
                returned.append(existing)
            elif event.start <= existing.start:
                existing.start = event.end
                returned.append(existing)
            elif event.end >= existing.end:
                existing.end = event.start
                returned.append(existing)
            else:
                old_start, old_end = existing.start, existing.end
                existing.start = event.end
                returned.append(Event(old_start, event.start, existing.title, existing.priority))
                returned.append(existing)

        # Lower/equal priority new event is trimmed around higher/equal existing
        curr_start = event.start
        for existing in [e for e in overlaps if e.priority >= event.priority]:
            if curr_start >= existing.end:
                continue
            if curr_start < existing.start:
                new_fragments.append(Event(curr_start, existing.start, event.title, event.priority))
            curr_start = max(curr_start, existing.end)

        if curr_start < event.end:
            new_fragments.append(Event(curr_start, event.end, event.title, event.priority))

        if new_fragments:
            self.events.extend(new_fragments)
            return new_fragments
        else:
            self.events.append(event)
            return returned

    def get_events(self, start: float, end: float) -> list[Event]:
        return sorted(
            [e for e in self.events if e.start < end and e.end > start],
            key=lambda e: e.start
        )

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> list[tuple[float, float]]:
        occupied = []
        for e in self.events:
            if e.start < end and e.end > start:
                occupied.append((max(e.start, start), min(e.end, end)))
        occupied.sort()

        merged = []
        for occ in occupied:
            if merged and occ[0] < merged[-1][1]:
                merged[-1] = (merged[-1][0], max(merged[-1][1], occ[1]))
            else:
                merged.append(list(occ))

        slots = []
        curr = start
        for occ_start, occ_end in merged:
            if curr < occ_start:
                if occ_start - curr >= min_duration:
                    slots.append((curr, occ_start))
            curr = max(curr, occ_end)
        if curr < end:
            if end - curr >= min_duration:
                slots.append((curr, end))
        return slots

    def utilization(self, start: float, end: float) -> float:
        if start >= end:
            return 0.0
        occupied = []
        for e in self.events:
            if e.start < end and e.end > start:
                occupied.append((max(e.start, start), min(e.end, end)))
        occupied.sort()

        total_occ = 0.0
        curr_end = start
        for occ_start, occ_end in occupied:
            if occ_start < curr_end:
                curr_end = max(curr_end, occ_end)
            else:
                total_occ += curr_end - start
                curr_end = occ_end
                start = occ_start
        total_occ += curr_end - start
        return total_occ / (end - start)

def regex_match(pattern: str, text: str) -> bool:
    nfa = [{'trans': {}, 'eps': []}]
    def new_state():
        nfa.append({'trans': {}, 'eps': []})
        return len(nfa) - 1

    def add_trans(s, c, t):
        nfa[s]['trans'].setdefault(c, []).append(t)

    def add_eps(s, t):
        nfa[s]['eps'].append(t)

    pos = 0
    n = len(pattern)

    def parse_concat():
        start = new_state()
        curr = start
        while pos < n and pattern[pos] not in '|)':
            frag = parse_atom()
            add_eps(curr, frag[0])
            curr = frag[1]
        return (start, curr)

    def parse_atom():
        nonlocal pos
        if pos >= n:
            return (new_state(), new_state())
        ch = pattern[pos]
        if ch == '(':
            pos += 1
            frag = parse_concat()
            if pos < n and pattern[pos] == ')':
                pos += 1
            return frag
        elif ch == '[':
            pos += 1
            neg = False
            if pos < n and pattern[pos] == '^':
                neg = True
                pos += 1
            chars = set()
            while pos < n and pattern[pos] != ']':
                if pos + 2 < n and pattern[pos+1] == '-' and pattern[pos+2] != ']':
                    for c in range(ord(pattern[pos]), ord(pattern[pos+2])+1):
                        chars.add(chr(c))
                    pos += 3
                else:
                    chars.add(pattern[pos])
                    pos += 1
            if pos < n:
                pos += 1
            s = new_state()
            e = new_state()
            if neg:
                nfa[s]['neg'] = chars
                add_eps(s, e)
            else:
                for c in chars:
                    add_trans(s, c, e)
            return (s, e)
        elif ch == '.':
            pos += 1
            s = new_state()
            e = new_state()
            nfa[s]['any'] = True
            add_eps(s, e)
            return (s, e)
        elif ch == '\\':
            pos += 1
            if pos < n:
                esc = pattern[pos]
                pos += 1
                s = new_state()
                e = new_state()
                nfa[s]['esc'] = esc
                add_eps(s, e)
                return (s, e)
        else:
            pos += 1
            s = new_state()
            e = new_state()
            add_trans(s, ch, e)
            return (s, e)

        if pos < n and pattern[pos] in '*+?':
            q = pattern[pos]
            pos += 1
            if q == '*':
                new_end = new_state()
                add_eps(frag[1], frag[0])
                add_eps(frag[1], new_end)
                frag = (frag[0], new_end)
            elif q == '+':
                new_end = new_state()
                add_eps(frag[1], frag[0])
                add_eps(frag[1], new_end)
                frag = (frag[0], new_end)
                nfa[frag[0]]['plus'] = True
            elif q == '?':
                new_end = new_state()
                add_eps(frag[0], new_end)
                add_eps(frag[1], new_end)
                frag = (frag[0], new_end)
            frag = (*frag, q)
            return frag
        return (*frag, None)

    frag = parse_concat()
    start_state = frag[0]
    end_state = frag[1]
    current_states = {start_state}

    def epsilon_closure(states):
        stack = list(states)
        closure = set(states)
        while stack:
            s = stack.pop()
            for t in nfa[s]['eps']:
                if t not in closure:
                    closure.add(t)
                    stack.append(t)
        return closure

    current_states = epsilon_closure(current_states)
    for char in text:
        next_states = set()
        for s in current_states:
            for c, targets in nfa[s]['trans'].items():
                if c == char:
                    next_states.update(targets)
            if nfa[s].get('any'):
                next_states.update(nfa[s]['eps'])
            if 'neg' in nfa[s]:
                if char not in nfa[s]['neg']:
                    next_states.update(nfa[s]['eps'])
            if 'esc' in nfa[s]:
                if char == nfa[s]['esc']:
                    next_states.update(nfa[s]['eps'])
            if nfa[s].get('plus'):
                next_states.update(nfa[s]['eps'])
        current_states = epsilon_closure(next_states)
    return end_state in current_states

