import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_virtual_nodes: int = 150):
        self.num_virtual_nodes = num_virtual_nodes
        self.ring = []  # Sorted list of (hash, vnode_name)
        self.virtual_to_physical = {}  # vnode_name -> node_id
        self.physical_nodes = set()  # Set of active node_ids

    def _hash(self, s: str) -> int:
        return int(hashlib.md5(s.encode()).hexdigest(), 16)

    def add_node(self, node_id: str) -> None:
        if node_id in self.physical_nodes:
            return
        self.physical_nodes.add(node_id)
        for i in range(self.num_virtual_nodes):
            vnode = f"{node_id}#v{i}"
            h = self._hash(vnode)
            self.virtual_to_physical[vnode] = node_id
            bisect.insort(self.ring, (h, vnode))

    def remove_node(self, node_id: str) -> None:
        if node_id not in self.physical_nodes:
            raise KeyError(node_id)

        self.physical_nodes.remove(node_id)

        # Identify virtual nodes to remove
        vnodes_to_remove = {f"{node_id}#v{i}" for i in range(self.num_virtual_nodes)}

        # Filter ring and clean mapping
        new_ring = []
        for h, vnode in self.ring:
            if vnode not in vnodes_to_remove:
                new_ring.append((h, vnode))
            else:
                del self.virtual_to_physical[vnode]
        self.ring = new_ring

    def get_node(self, key: str) -> str | None:
        if not self.physical_nodes:
            return None

        h = self._hash(key)
        # bisect_left finds the first element >= (h, "")
        # Since "" is lexicographically smaller than any vnode name,
        # this effectively finds the first vnode with hash >= h.
        idx = bisect.bisect_left(self.ring, (h, ""))

        if idx == len(self.ring):
            idx = 0

        vnode = self.ring[idx][1]
        return self.virtual_to_physical[vnode]

    def get_nodes_for_key(self, key: str, num_replicas: int = 3) -> list[str]:
        if not self.physical_nodes or num_replicas <= 0:
            return []

        h = self._hash(key)
        idx = bisect.bisect_left(self.ring, (h, ""))
        if idx == len(self.ring):
            idx = 0

        n = len(self.ring)
        result = []
        seen = set()

        # Traverse clockwise starting from the found index
        for i in range(n):
            current_idx = (idx + i) % n
            vnode = self.ring[current_idx][1]
            node_id = self.virtual_to_physical[vnode]

            if node_id not in seen:
                seen.add(node_id)
                result.append(node_id)
                if len(result) == num_replicas:
                    break

        return result
